/**
 * Get all document types for a specific tool and category
 */
export function getDocumentTypes(toolId: string, category: string): string[] {
  const normalizedToolId = toolId.toLowerCase().replace(/^the\s+/, '').replace(/\s+/g, '-');
  const normalizedCategory = category.toLowerCase();
  
  return ALL_DOCUMENT_MAPPINGS
    .filter(m => 
      m.tool === normalizedToolId && 
      m.documentCategory.toLowerCase() === normalizedCategory
    )
    .map(m => m.documentType);
}

/**
 * Get editor type for a specific document
 */
export function getEditorType(toolId: string, category: string, documentType: string): string {
  const normalizedToolId = toolId.toLowerCase().replace(/^the\s+/, '').replace(/\s+/g, '-');
  const mapping = ALL_DOCUMENT_MAPPINGS.find(m => 
    m.tool === normalizedToolId && 
    m.documentCategory === category &&
    m.documentType === documentType
  );
  
  return mapping?.editor || 'Slide-Based Presentation Editor';
}

/**
 * Get statistics about the document mappings
 */
export function getMappingStats() {
  const tools = new Set(ALL_DOCUMENT_MAPPINGS.map(m => m.tool));
  const totalDocs = ALL_DOCUMENT_MAPPINGS.length;
  
  const byTool: Record<string, number> = {};
  ALL_DOCUMENT_MAPPINGS.forEach(m => {
    byTool[m.tool] = (byTool[m.tool] || 0) + 1;
  });
  
  return {
    totalTools: tools.size,
    totalDocuments: totalDocs,
    byTool,
    tools: Array.from(tools),
  };
}
